import React, { type PropsWithChildren } from "react";
import { ResponsiveElement, useSeparator } from "../../factory";
import type {IStackProps, IStyleClasses} from "@lmb-it/kitsconcerto-types";

const spaceScale: Record<string, string> = {
    xs: "0.25rem",
    sm: "0.5rem",
    md: "0.75rem",
    lg: "1rem",
    xl: "1.25rem",
    "2xl": "1.5rem",
    "3xl": "1.75rem",
    "4xl": "2rem",
};
type IsolatedStack = Omit<IStackProps, keyof IStyleClasses>
const VStack: React.FC<PropsWithChildren<IStackProps>> = (props) => {
    const { cssProps, nativeProps } = useSeparator<IsolatedStack>(props);
    const { space = "md", reversed = false, children, style, entering, exiting, ...rest } = nativeProps;

    const additionalStyles:IStyleClasses = {
        display: "flex",
        flexDirection: reversed ? "column-reverse" : "column",
        gap: spaceScale[space] ?? spaceScale.md,
    };

    return (
        <ResponsiveElement<IsolatedStack>
            ref={props.ref}
            entering={entering}
            exiting={exiting}
            nativeProps={rest}
            cssProps={cssProps}
            additionalStyles={additionalStyles}
        >
            {children}
        </ResponsiveElement>
    );
};

export default VStack;
